const enabled = $env.N8N_WORKFLOW_FRONTEND_INCIDENT_TRIAGE_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: true, shouldSendSlack: false, responseCode: 503, responseBody: { ok: false, code: 'WORKFLOW_DISABLED', message: 'Frontend incident triage disabled' } } }];
}

const crypto = require('crypto');
const secret = $env.N8N_FRONTEND_INCIDENT_WEBHOOK_SECRET;
if (!secret) {
  return [{ json: { killed: true, shouldSendSlack: false, responseCode: 503, responseBody: { ok: false, code: 'CONFIG_MISSING_SECRET', message: 'Missing frontend incident webhook secret' } } }];
}

function sortKeys(obj) {
  if (Array.isArray(obj)) return obj.map(sortKeys);
  if (obj !== null && typeof obj === 'object') {
    return Object.keys(obj).sort().reduce((acc, key) => {
      acc[key] = sortKeys(obj[key]);
      return acc;
    }, {});
  }
  return obj;
}

const envelope = $input.first().json;
const headers = envelope.headers || {};
const body = envelope.body || {};
const signature = headers['x-webhook-signature'] || '';
const canonicalBody = JSON.stringify(sortKeys(body));
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(canonicalBody).digest('hex');
const sigBuf = Buffer.from(signature);
const expBuf = Buffer.from(expected);
if (sigBuf.length !== expBuf.length || !crypto.timingSafeEqual(sigBuf, expBuf)) {
  return [{ json: { killed: true, shouldSendSlack: false, responseCode: 401, responseBody: { ok: false, code: 'AUTH_INVALID_SIGNATURE', message: 'Invalid webhook signature' } } }];
}

const incidents = Array.isArray(body.incidents) ? body.incidents : [];
const summary = body.summary || {};
const mode = body.mode || 'unknown';
const failed = Number(summary.failed || incidents.length || 0);
const passed = Number(summary.passed || 0);
const total = Number(summary.total || incidents.length || 0);
const runUrl = body.run_url || null;
const repo = body.repo || 'unknown';
const sha = body.sha ? String(body.sha).slice(0, 7) : 'unknown';
const titleLines = incidents.slice(0, 5).map((incident, index) => `${index + 1}. ${incident.contract_id || 'unknown'} — ${incident.error_summary || incident.title || 'failure'}`);
const digestLines = [
  `Aspire desktop frontend synthetics`,
  `mode: ${mode}`,
  `repo: ${repo}`,
  `sha: ${sha}`,
  `summary: ${passed}/${total} passed, ${failed} failed`,
  runUrl ? `run: ${runUrl}` : null,
  incidents.length > 0 ? 'top incidents:' : 'no incidents detected',
  ...titleLines,
].filter(Boolean);
const requestId = 'frontend-incident-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = headers['x-correlation-id'] || requestId;
return [{ json: {
  killed: false,
  requestId,
  correlationId,
  incidentCount: incidents.length,
  shouldSendSlack: incidents.length > 0 && !!$env.N8N_FRONTEND_INCIDENT_SLACK_WEBHOOK,
  incidents,
  summary: { total, passed, failed, skipped: Number(summary.skipped || 0) },
  slackText: digestLines.join('\n'),
  responseCode: 202,
  responseBody: {
    ok: true,
    status: 'accepted',
    mode,
    incidentCount: incidents.length,
    failed,
    runUrl,
    requestId,
    correlationId
  }
} }];
